function diffCell(value, cls) {
  if (value === undefined || value === null) return '<td>—</td>'
  return `<td class="diff-${cls}">${value}</td>`
}

function buildMeridianChartHtml() {
  const rows = MERIDIAN_CHART_DATA.flatMap(group =>
    group.songs.map((song, i) => {
      const charCell = i === 0
        ? `<td class="chart-char" rowspan="${group.songs.length}">${group.char}</td>`
        : ''
      return `<tr>${charCell}<td class="chart-song">${song.name}</td>${diffCell(song.easy,'easy')}${diffCell(song.normal,'normal')}${diffCell(song.hard,'hard')}</tr>`
    })
  ).join('')
  return `<table class="chart-table"><thead><tr><th>角色</th><th>歌曲</th><th>Easy</th><th>Normal</th><th>Hard</th></tr></thead><tbody>${rows}</tbody></table>`
}

